UMAP

rm(list = ls())
### load packages
pacman::p_load(
  tidyverse,
  umap,
  palmerpenguins
)
### theme set
theme_set(theme_bw(18))
### subset data
penguins &lt;- penguins |&gt; 
  drop_na() |&gt; 
  select(-year) |&gt; 
  mutate(ID = row_number())

### meta data
penguins_meta &lt;- penguins |&gt; 
  select(ID, species, island, sex)
### umap analysis
set.seed(123)
umap_fit &lt;- penguins |&gt;
  select(where(is.numeric)) |&gt; 
  column_to_rownames("ID") |&gt; 
  scale() |&gt; 
  umap()
### retrieve data from umap analysis
umap_df &lt;- umap_fit$layout |&gt; 
  as.data.frame() |&gt; 
  rename(UMAP1 = "V1", UMAP2 = "V2") |&gt; 
  mutate(ID = row_number()) |&gt; 
  inner_join(penguins_meta, by = "ID")  
### visualize umap
umap_df |&gt; 
  ggplot(aes(x = UMAP1, y = UMAP2, color = species, shape = sex)) +
  geom_point() +
  labs(x = "UMAP1", y = "UMAP2", title = "UMAP plot")







### facet by island
umap_df |&gt; 
  ggplot(aes(x = UMAP1, y = UMAP2, color = species))+
  geom_point(size = 3, alpha = 0.5) +
  facet_wrap(~island) +
  labs(x = "UMAP1", y = "UMAP2", subtitle = "UMAP plot") +
  theme(legend.position = "bottom")







### circlize the outlier cases
pacman::p_load(
  ggforce
)
umap_df |&gt; 
  ggplot(aes(x = UMAP1, y = UMAP2, color = species, shape = sex)) +
  geom_point()+
  labs(x = "UMAP1", y = "UMAP2", subtitle = "UMAP plot") +
  geom_circle(aes(x0 = -5, y0= -3.8, r = 0.65), color = "green", inherit.aes = FALSE)

tSNE

rm(list = ls())
### load packages
pacman::p_load(
  tidyverse,
  Rtsne,
  palmerpenguins
)
### theme set
theme_set(theme_bw(18))
### subset data
penguins &lt;- penguins |&gt; 
  drop_na() |&gt; 
  select(-year) |&gt; 
  mutate(ID = row_number())

### meta data
penguins_meta &lt;- penguins |&gt; 
  select(ID, species, island, sex)

### tSNE analysis
set.seed(135)
tsne_fit &lt;- penguins |&gt; 
  select(where(is.numeric)) |&gt; 
  column_to_rownames("ID") |&gt; 
  scale() |&gt; 
  Rtsne()

### retrive data
tsne_df  &lt;- tsne_fit$Y |&gt; 
  as.data.frame() |&gt; 
  rename(tSNE1 = "V1", tSNE2 = "V2") |&gt; 
  mutate(ID = row_number())

tsne_df &lt;- tsne_df |&gt; 
  inner_join(penguins_meta, by = "ID")

### check data
head(tsne_df)
